/**
 * analyze.ts — Audio analysis via python/librosa
 *
 * Calls the analyze-audio.py script for BPM, key, energy, spectral,
 * and rhythm density analysis. Returns structured data or null on failure.
 */

import { execSync } from "child_process";
import { join, dirname } from "path";
import { resolveBin } from "../../libs/resolve-bin.js";
import { PROJECT_ROOT } from "../../libs/paths.js";

export interface AudioAnalysis {
  bpm: number;
  key: { key: string; mode: string; confidence: number; label: string };
  energy: { rms: number; level: string; dynamics: string };
  spectral: { centroid: number; brightness: string; bandwidth: number; width: string };
  rhythm: { onsetsPerSec: number; density: string };
}

/**
 * Run librosa analysis on an audio file.
 * Returns null if python or librosa is unavailable — callers should fall back gracefully.
 */
export function analyzeAudio(audioFile: string): AudioAnalysis | null {
  try {
    const pythonBin = resolveBin("python", PROJECT_ROOT);
    // analyze-audio.py lives next to the old musiccard.ts (src/tools/)
    const analyzeScript = join(dirname(new URL(import.meta.url).pathname.replace(/^\/([A-Z]:)/, "$1")), "..", "analyze-audio.py");

    const raw = execSync(
      `"${pythonBin}" "${analyzeScript}" "${audioFile}"`,
      { encoding: "utf-8", timeout: 120_000, stdio: ["pipe", "pipe", "pipe"] },
    );

    const result = JSON.parse(raw.trim());
    if ("error" in result) return null;
    return result as AudioAnalysis;
  } catch {
    return null;
  }
}

