/**
 * card.ts — Build the markdown music card from profile + analysis data
 *
 * Pure function — takes data in, returns markdown string out.
 */

import type { GenreProfile, YtMeta } from "./profiles.js";
import type { AudioAnalysis } from "./analyze.js";

export interface CardInput {
  meta: YtMeta;
  profile: GenreProfile;
  audioAnalysis: AudioAnalysis | null;
  audioSlug: string;
  cardType: string;
  sampleLabel: string;
  durationLabel: string;
  sourceUrl: string;
  today: string;
}

export function buildCard(input: CardInput): string {
  const { meta, profile, audioAnalysis, audioSlug, cardType, sampleLabel, durationLabel, sourceUrl, today } = input;

  // Override profile with real audio data where available
  if (audioAnalysis) {
    profile.bpm = `${audioAnalysis.bpm} BPM`;
    profile.key = `${audioAnalysis.key.label} (confidence: ${audioAnalysis.key.confidence})`;

    const energyDesc = `${audioAnalysis.energy.level} — ${audioAnalysis.energy.dynamics}`;
    profile.energy = profile.energy ? `${energyDesc} (${profile.energy})` : energyDesc;

    const spectralDesc = `${audioAnalysis.spectral.brightness}, ${audioAnalysis.spectral.width} spectrum`;
    profile.texture = profile.texture ? `${spectralDesc}; ${profile.texture}` : spectralDesc;
  }

  const ytTags = meta.tags.slice(0, 10).map(t => t.toLowerCase().replace(/\s+/g, "-"));

  return `---
title: "${escapeYaml(meta.title)}"
type: ${cardType}
source: ${sourceUrl}
channel: "${escapeYaml(meta.channel)}"
sample: "${sampleLabel}"
duration: ${durationLabel}
created: ${today}
tags: [${ytTags.join(", ")}]
---

## Audio

![[${audioSlug}.mp3]]

## Profile

| Attribute | Value |
|-----------|-------|
| **BPM** | ${profile.bpm} |
| **Key** | ${profile.key} |
| **Mood** | ${profile.mood} |
| **Energy** | ${profile.energy} |
| **Texture** | ${profile.texture} |

## Groove

${profile.groove || "<!-- Describe the rhythmic feel, drum patterns, bass behavior, swing/straight -->"}

## Palette

- **Lead:** ${profile.lead}
- **Harmony:** ${profile.harmony}
- **Bass:** ${profile.bass}
- **Drums:** ${profile.drums}
- **Texture:** ${profile.texturePalette}

## Suno Translation

\`\`\`
${profile.sunoTags || "<!-- Comma-separated Suno style tags derived from the audio -->"}
\`\`\`

## MiniMax Translation

\`\`\`
${profile.minimaxPrompt || "<!-- Natural-language MiniMax prompt describing the track -->"}
\`\`\`

## Notes

Source: ${meta.channel} — ${Math.floor(meta.duration / 60)}m${meta.duration % 60}s total. Sample: ${sampleLabel}.
`;
}

function escapeYaml(str: string): string {
  return str.replace(/"/g, '\\"');
}
